#include <stdio.h>
#include <stdlib.h>
#include <math.h>

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long lcm(long long a, long long b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long a, b, c;
        scanf("%lld %lld %lld", &a, &b, &c);
        long long count = 0;
        for (long long x = 1; x <= 1000000; x++) {
            for (long long y = 1; y <= 1000000; y++) {
                if (x * y == a + b * lcm(x, y) + c * gcd(x, y)) count++;
            }
        }
        if (count == 0) printf("0\n");
        else if (count > 1000000) printf("-1\n");
        else printf("%lld\n", count);
    }
    return 0;
}

